+        assert_eq!(r.title, "");
+        assert_eq!(r.body, "");
+        assert!(r.from_agent.is_none());
+        assert!(r.importance.is_none());
+        assert!(r.thread_id.is_none());
+        assert!(r.created_ts.is_none());
+        assert!(r.project_id.is_none());
+    }
